#Loading animation for the forest generat
def loading_text():
    intro_text=['Generating Forest','Generating Forest.','Generating Forest..','Generating Forest...','Generating Forest....']
    CLEAR_LINE = '\033[K'
    for i in 2*intro_text :
        time.sleep(0.4)
        print('\r'+i+CLEAR_LINE, end="",flush=True)
    print('''\r\033[KForest Generated!\033[0m''',end=" ",flush=True)
    time.sleep(1.1)
    print('\r'+CLEAR_LINE)

