#Line separator for the loading screen
def line():
    print("",end='');slowprint(150*("в•җ"));print("")

#Line separator for the loading screen
def slowprint(str):
    for i in str:
        sys.stdout.write(i)
        sys.stdout.flush()
        time.sleep(0.005)
